INSERT INTO `announcements` (`id`, `title`, `content`, `created_at`, `is_active`) VALUES
(2, '【更新】新版本发布啦！', '### v1.0.0 (2024-01-20)\n- 初始版本发布\n- 实现用户注册/登录\n- 实现视频管理\n- 实现轮播图管理\n- 实现用户关注功能\n- 实现消息功能\n- 实现后台管理系统', '2026-01-21 15:10:28', 1),
(8, '版本更新V1.0.5', '1.用户主页优化 \n- 修复 Vue 3 兼容性问题（ $on → getOpenerEventChannel ） - 优化布局：背景图独立区域，头像卡片负边距覆盖 \n- 修复背景图显示（后端 API 添加 background_image 字段） \n- 修复导航栏标题居中问题 \n2. 视频播放功能优化 \n- 优化 VideoItem 组件，添加视频播放功能 \n- 实现首页视频自动播放（类似抖音） \n- 修复视频滑动问题（改用 scroll-view） \n- 优化视频显示比例和图层显示 \n- 移除点击视频跳转播放器页面的功能 \n- 底部导航栏修复 \n- 移除测试用的小红点和数字角标', '2026-01-21 20:50:47', 1),
(12, '版本更新V1.0.6', '版本更新V1.0.6', '2026-01-24 22:48:02', 1);
